local function point_in_polygon(x, y, poly)
  -- Ray-casting algorithm
  local inside = false
  local n = #poly
  local j = n
  for i = 1, n do
    local xi, yi = poly[i][1], poly[i][2]
    local xj, yj = poly[j][1], poly[j][2]
    if ((yi > y) ~= (yj > y)) and
       (x < (xj - xi) * (y - yi) / (yj - yi) + xi) then
      inside = not inside
    end
    j = i
  end
  return inside
end

function shapes.getShapeAt(x, y)
  for _, shape in ipairs(shapesData) do
    local bb = shape.bbox
    if x >= bb[1] and x <= bb[3] and y >= bb[2] and y <= bb[4] then
      if point_in_polygon(x, y, shape.polygon) then
        return shape.name
      end
    end
  end
  return "?"
end

return shapes
